import { BeFramework } from '@be/surprises';

export default class Analytics {
    private skill:BeFramework.BeSkill;

    constructor(skill:BeFramework.BeSkill) {
        this.skill = skill;
    }

    public offeredOta(response:'accepted'|'rejected'|'ignored') {
        this.skill.track('OTA Update Offered', { accepted: response });
    }

    public offeredNotes(response:'accepted'|'rejected'|'ignored') {
        this.skill.track('OTA Notes Offered', { accepted: response });
    }

    public deliveredNotes(isReactive:boolean, version:string) {
        this.skill.track('OTA Notes Delivered', { intent:isReactive ? 'reactive' : 'proactive', release_version:version });
    }

    public updated(version:string) {
        this.skill.track('OTA Update Installed', { release_version:version });
    }
}
